using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace YourNamespace.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class UploadController : ControllerBase
    {
        private const string UploadsDirectory = "wwwroot/uploads";

        [HttpPost("avatar")]
        public IActionResult UploadAvatar(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest();

            var extension = Path.GetExtension(file.FileName);
            var allowedExtensions = new[] { ".png", ".jpg", ".jpeg" }; // Add more extensions as needed
            if (!allowedExtensions.Contains(extension))
                return StatusCode(StatusCodes.Status415UnsupportedMediaType);

            var filePath = Path.Combine(UploadsDirectory, Guid.NewGuid().ToString() + extension);
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(new { path = filePath });
        }

        [HttpPost("document")]
        public IActionResult UploadDocument(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest();

            var extension = Path.GetExtension(file.FileName);
            var allowedExtensions = new[] { ".pdf", ".docx", ".xlsx" }; // Add more extensions as needed
            if (!allowedExtensions.Contains(extension))
                return StatusCode(StatusCodes.Status415UnsupportedMediaType);

            var filePath = Path.Combine(UploadsDirectory, Guid.NewGuid().ToString() + extension);
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(new { path = filePath });
        }
    }
